import { Routes, Route, useParams } from "react-router-dom";
import Home from "./Home";
import React, { useRef, useEffect, useState } from "react";
import { io } from "socket.io-client";

// 🔗 CONNECT TO SERVER + ROOM
const ROOM_ID = "room1";

const socket = io("http://localhost:5006", {
  query: { room: ROOM_ID },
});

function App() {
  const canvasRef = useRef(null);
  const drawing = useRef(false);

  const [color, setColor] = useState("#000000");
  const [tool, setTool] = useState("pen");
  const [brushSize, setBrushSize] = useState(2);

  const [history, setHistory] = useState([]);
  const [redoStack, setRedoStack] = useState([]);

  // 🔌 SOCKET EVENTS
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    socket.on("draw", (data) => drawLine(ctx, data));

    socket.on("clear", () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
    });
  }, []);

  // 🖊 START / STOP DRAW
  const startDrawing = () => {
    drawing.current = true;
  };

  const stopDrawing = () => {
    drawing.current = false;
    const ctx = canvasRef.current.getContext("2d");
    ctx.beginPath();

    // Save history
    const canvas = canvasRef.current;
    setHistory((prev) => [...prev, canvas.toDataURL()]);
    setRedoStack([]);
  };

  // ✏️ DRAW FUNCTION
  const draw = (e) => {
    if (!drawing.current) return;

    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();

    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;

    const data = {
      x,
      y,
      color,
      tool,
      size: brushSize,
    };

    drawLine(canvas.getContext("2d"), data);
    socket.emit("draw", data);
  };

  // 🎨 DRAW LINE
  const drawLine = (ctx, { x, y, color, tool, size }) => {
    if (tool === "eraser") {
      ctx.globalCompositeOperation = "destination-out";
    } else {
      ctx.globalCompositeOperation = "source-over";
      ctx.strokeStyle = color;
    }

    ctx.lineWidth = size;
    ctx.lineTo(x, y);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(x, y);
  };

  // 🧹 CLEAR CANVAS
  const clearCanvas = () => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");

    ctx.clearRect(0, 0, canvas.width, canvas.height);
    socket.emit("clear");

    setHistory([]);
    setRedoStack([]);
  };

  // 💾 DOWNLOAD IMAGE
  const downloadImage = () => {
    const canvas = canvasRef.current;
    const link = document.createElement("a");
    link.download = "whiteboard.png";
    link.href = canvas.toDataURL();
    link.click();
  };

  // ↩ UNDO
  const undo = () => {
    if (history.length < 2) return;

    const newHistory = [...history];
    const last = newHistory.pop();

    setRedoStack((prev) => [last, ...prev]);
    setHistory(newHistory);

    const img = new Image();
    img.src = newHistory[newHistory.length - 1];

    img.onload = () => {
      const ctx = canvasRef.current.getContext("2d");
      ctx.clearRect(0, 0, 800, 500);
      ctx.drawImage(img, 0, 0);
    };
  };

  // ↪ REDO
  const redo = () => {
    if (redoStack.length === 0) return;

    const imgData = redoStack[0];

    const img = new Image();
    img.src = imgData;

    img.onload = () => {
      const ctx = canvasRef.current.getContext("2d");
      ctx.clearRect(0, 0, 800, 500);
      ctx.drawImage(img, 0, 0);
    };

    setHistory((prev) => [...prev, imgData]);
    setRedoStack((prev) => prev.slice(1));
  };

  // 📱 TOUCH SUPPORT
  const handleTouchMove = (e) => {
    const touch = e.touches[0];
    draw({
      clientX: touch.clientX,
      clientY: touch.clientY,
    });
  };

  return (
    <div style={{ textAlign: "center" }}>
      <h2>Real-Time Whiteboard 🎨</h2>

      {/* 🎨 COLOR */}
      <input
        type="color"
        value={color}
        onChange={(e) => setColor(e.target.value)}
      />

      {/* ✏️ PEN */}
      <button onClick={() => setTool("pen")}>Pen</button>

      {/* 🧽 ERASER */}
      <button onClick={() => setTool("eraser")}>Eraser</button>

      {/* 📏 BRUSH SIZE */}
      <div>
        <label>Size: {brushSize}</label>
        <input
          type="range"
          min="1"
          max="30"
          value={brushSize}
          onChange={(e) => setBrushSize(Number(e.target.value))}
        />
      </div>

      {/* 🧹 CLEAR */}
      <button onClick={clearCanvas}>Clear</button>

      {/* 💾 DOWNLOAD */}
      <button onClick={downloadImage}>Download</button>

      {/* ↩ UNDO / REDO */}
      <button onClick={undo}>Undo</button>
      <button onClick={redo}>Redo</button>

      <br /><br />

      <canvas
        ref={canvasRef}
        width={800}
        height={500}
        style={{ border: "2px solid black" }}
        onMouseDown={startDrawing}
        onMouseUp={stopDrawing}
        onMouseMove={draw}
        onTouchStart={startDrawing}
        onTouchEnd={stopDrawing}
        onTouchMove={handleTouchMove}
      />
    </div>
  );
}

export default App;
